    else:
            url = "http://{}:{}{}".format(app.config.get('FQDN'), app.config.get('API_PORT'), '/login')
    if current_user.is_authenticated():
        auth_dict = {
            "authenticated": True,
            "user": current_user.email,
            "roles": current_user.role,
        }
    else:
        auth_dict = {
