            // Get length and close the connection.
            header('Content-Length: ' . ob_get_length());
            header('Connection: close');

            ob_end_flush();
            @ob_flush();
            flush();
        }
    }

    // Run any time consuming tasks.
    $this->fireEvent('onShutdown');
}

